-- ─────────────────────────────────────────────────────────────────────────────
-- Import grile: Pedodonție
-- ─────────────────────────────────────────────────────────────────────────────
-- Generated from grile_pedo_final.xlsx
-- Total questions: 1179
-- Total options:   5895
--
-- Aborts if chapter "Pedodonție" already exists.
--
-- Usage:
--   psql "<DATABASE_PUBLIC_URL>" -f scripts/sql/04-import-pedo.sql
-- ─────────────────────────────────────────────────────────────────────────────

SET client_encoding TO 'UTF8';

BEGIN;

-- 1. Refuse if chapter exists already.
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM chapters WHERE name = 'Pedodonție') THEN
    RAISE EXCEPTION 'Chapter "Pedodonție" already exists — refusing to re-import.';
  END IF;
END $$;

-- 2. Insert chapter (sort_order = max + 1) and capture its id.
VALUES ('Pedodonție', (SELECT COALESCE(MAX(sort_order), -1) + 1 FROM chapters))
RETURNING id AS chapter_id \gset

-- 3. Bulk-insert all 1179 questions with pre-generated UUIDs.

-- 4. Bulk-insert all 5895 options.

-- 5. Sanity check.
\echo ''
\echo '── Import summary ────────────────────────────────────────────────────────'
SELECT COUNT(*)::int AS inserted_questions FROM questions WHERE source_book = 'Pedodonție';
SELECT COUNT(*)::int AS inserted_options FROM options o JOIN questions q ON q.id = o.question_id WHERE q.source_book = 'Pedodonție';

COMMIT;